def test_generator2():
    acc = 0
    for i in range(10):
        r = yield acc
        acc += i * r
c = test_generator2()
result, result2 = run_js('''
(c) => {
  let {done, value} = c.next();
  let result = [];
  while(!done){
    result.push(value);
    ({done, value} = c.next(value + 1));
  }
  function* test(){
    let acc = 0;
    for(let i=0; i < 10; i++){
      let r = yield acc;
      acc += i * r;
    }
  }
  c = test();
  ({done, value} = c.next());
  let result2 = [];
  while(!done){
    result2.push(value);
    ({done, value} = c.next(value + 1));
  }
  return [result, result2];
}
''')(c)
